class CodeGenManager(GroupChatManager):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.success_criteria = ["tests passed", "all checks green", "code validated"]

    def select_speaker(self, last_speaker, groupchat):
        last_message = groupchat.messages[-1]['content'].lower()
        if any(criteria in last_message for criteria in self.success_criteria):
            return None  # Terminate
        return super().select_speaker(last_speaker, groupchat)

manager = CodeGenManager(groupchat=groupchat)

