def vex_code_safety_check(code: str) -> dict:
    policy = {
        "block_patterns": [
            r"exec\(", r"eval\(", r"__import__\('os'\)",
            r"open\(.*'w'\)", r"requests\.get\(",
            r"pip\.|subprocess"
        ],
        "dependency_whitelist": ["pandas", "numpy", "matplotlib"],
        "max_file_size": 1024
    }

    result = vex.verify_code(code, policy)
    return {
        'safe': result.approved,
        'issues': result.issues,
        'sanitized_code': result.sanitized_code
    }

