def vex_drift_monitor(groupchat):
    conversation = " ".join([m['content'] for m in groupchat.messages[-10:]])

    drift_check = vex.verify_conversation(
        conversation,
        context="code generation for CSV processing",
        max_rounds=15
    )

    if drift_check.drift_detected:
        return f"[VEX ALERT] Conversation drifting. Focus: {drift_check.suggested_refocus}"

    if len(groupchat.messages) > 12:
        return "[VEX] Max iterations reached. Terminating."

    return None

